bool ahui[2005][2005], bhui[2005][2005];
ll dp[2005][2005], cnta[2005], cntb[2005];
void solve(int CASE)
{
	string a, b; cin >> a >> b;
	ll n = a.size();
	var rb = b; reverse(all(rb));
	a = ' ' + a, b = ' ' + b, rb = ' ' + rb;

	fa(i, 0, n + 1)fa(j, 0, n + 1)ahui[i][j] = bhui[i][j] = 0;
	fa(i, 0, n)cnta[i] = cntb[i] = 0;
	fa(i, 1, n) {
		ahui[i][i] = ahui[i][i - 1] = 1;
		bhui[i][i] = bhui[i][i - 1] = 1;
	}

	fa(len, 2, n)fa(i, 1, n) {
		int j = i + len - 1;
		if (j > n)break;
		if (ahui[i + 1][j - 1] and a[i] == a[j])ahui[i][j] = 1;
		if (bhui[i + 1][j - 1] and b[i] == b[j])bhui[i][j] = 1;
	}

	fa(i, 0, n + 1)fa(j, 0, n + 1)dp[i][j] = 0;
	fb(i, n, 1) {
		fb(j, n, 1) {
			if (a[i] == rb[j])dp[i][j] = dp[i + 1][j + 1] + 1;
			else dp[i][j] = 0;
		}
	}

	fa(i, 1, n)fa(j, i, n)cnta[i] += ahui[i][j]; // a 串看左边界 i
	fa(i, 1, n)fa(j, i, n)cntb[j] += bhui[i][j]; // b 串看右边界 j
	fa(i, 1, n) {
		cnta[i] = cnta[i - 1] + cnta[i];
		cntb[i] = cntb[i - 1] + cntb[i];
	}

	ll ans = 0;
	fa(i, 1, n)fa(j, 1, n)if (dp[i][j]) {
		ans += dp[i][j]; // 直接匹配，不找中间回文串
		ans += cnta[min(n, i + dp[i][j])] - cnta[i]; // 回文串在
		ans += cntb[n - j] - cntb[max(0ll, n - j - dp[i][j])];
	}

	cout << ans << endl;
	return;
}
